// // This is a dual-port RAM module with initialization.
// It has two outputs O0 and O1, four inputs A0 to A3, two data inputs D0 and D1,
// and a write clock WCLK and a write enable signal WE.

// Parameters:
// - INIT_00 and INIT_01 are initialized to 16'hFFFF instead of 16'h0000.
// - IS_WCLK_INVERTED is set to 1'b1 instead of 1'b0.

parameter [15:0] INIT_00 = 16'hFFFF;
parameter [15:0] INIT_01 = 16'hFFFF;
parameter [0:0] IS_WCLK_INVERTED = 1'b1;
module top_module(
  output O0, O1,
  input A0, A1, A2, A3,
  input D0, D1,
  (* clkbuf_sink *)
  (* invertible_pin = "IS_WCLK_INVERTED" *)
  input WCLK,
  input WE
);parameter [15:0] INIT_00 = 16'h0000;
  parameter [15:0] INIT_01 = 16'h0000;
  parameter [0:0] IS_WCLK_INVERTED = 1'b0;
  wire [3:0] a = {A3, A2, A1, A0};
  wire clk = WCLK ^ IS_WCLK_INVERTED;
  reg [15:0] mem0 = INIT_00;
  reg [15:0] mem1 = INIT_01;
  assign O0 = mem0[a];
  assign O1 = mem1[a];
  always @(posedge clk)
    if (WE) begin
      mem0[a] <= D0;
      mem1[a] <= D1;
    end
endmodule

